import{_ as a,o as d,c as r,ai as e}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第十八课：选股思路","description":"","frontmatter":{},"headers":[],"relativePath":"guide/18-stock-picking.md","filePath":"guide/18-stock-picking.md","lastUpdated":0}'),l={name:"guide/18-stock-picking.md"};function i(h,t,o,n,s,b){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第十八课-选股思路" tabindex="-1">第十八课：选股思路 <a class="header-anchor" href="#第十八课-选股思路" aria-label="Permalink to “第十八课：选股思路”">​</a></h1><p>A股有5000多只股票，如何选出值得买的？这一课介绍三种选股思路。</p><h2 id="一、三大选股维度" tabindex="-1">一、三大选股维度 <a class="header-anchor" href="#一、三大选股维度" aria-label="Permalink to “一、三大选股维度”">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>关注点</th><th>适合人群</th></tr></thead><tbody><tr><td>消息面</td><td>政策、公告、研报</td><td>短线操作</td></tr><tr><td>技术面</td><td>K线、均线、成交量</td><td>趋势交易</td></tr><tr><td>基本面</td><td>业绩、估值、行业</td><td>中长线投资</td></tr></tbody></table><blockquote><p>💡 <strong>建议新手以基本面为主，技术面为辅</strong>。</p></blockquote><h2 id="二、消息面选股" tabindex="-1">二、消息面选股 <a class="header-anchor" href="#二、消息面选股" aria-label="Permalink to “二、消息面选股”">​</a></h2><h3 id="_1-政策利好" tabindex="-1">1. 政策利好 <a class="header-anchor" href="#_1-政策利好" aria-label="Permalink to “1. 政策利好”">​</a></h3><p>国家政策扶持 = 行业机会。</p><table tabindex="0"><thead><tr><th>政策信号</th><th>可能受益板块</th></tr></thead><tbody><tr><td>新能源补贴</td><td>整车、电池</td></tr><tr><td>芯片国产替代</td><td>半导体设备</td></tr><tr><td>医改</td><td>创新药</td></tr><tr><td>房地产松绑</td><td>地产链</td></tr></tbody></table><h3 id="_2-公告挖掘" tabindex="-1">2. 公告挖掘 <a class="header-anchor" href="#_2-公告挖掘" aria-label="Permalink to “2. 公告挖掘”">​</a></h3><p>上市公司公告包含重要信息：</p><table tabindex="0"><thead><tr><th>公告类型</th><th>信息含义</th></tr></thead><tbody><tr><td>业绩预增</td><td>净利润大幅增长，可能是利好</td></tr><tr><td>重大合同</td><td>有了大客户，业绩有保障</td></tr><tr><td>高送转</td><td>股票拆分，对资金面有影响</td></tr><tr><td>减持公告</td><td>股东在卖，小心</td></tr></tbody></table><h3 id="_3-研报追踪" tabindex="-1">3. 研报追踪 <a class="header-anchor" href="#_3-研报追踪" aria-label="Permalink to “3. 研报追踪”">​</a></h3><p>机构研报透露专业判断：</p><ul><li><strong>首次覆盖</strong>：机构第一次研究，可能看好</li><li><strong>目标价</strong>：机构认为能涨到多少</li><li><strong>评级上调</strong>：机构更看好了</li></ul><h2 id="三、技术面选股" tabindex="-1">三、技术面选股 <a class="header-anchor" href="#三、技术面选股" aria-label="Permalink to “三、技术面选股”">​</a></h2><h3 id="_1-趋势选股" tabindex="-1">1. 趋势选股 <a class="header-anchor" href="#_1-趋势选股" aria-label="Permalink to “1. 趋势选股”">​</a></h3><p>顺势而为，只做上涨趋势的股票：</p><ul><li>股价在20日均线上方</li><li>均线多头排列</li><li>成交量配合放大</li></ul><h3 id="_2-突破选股" tabindex="-1">2. 突破选股 <a class="header-anchor" href="#_2-突破选股" aria-label="Permalink to “2. 突破选股”">​</a></h3><p>在股价突破重要位置时买入：</p><ul><li>突破前期高点</li><li>突破震荡区间</li><li>突破均线压力</li></ul><h3 id="_3-超跌选股" tabindex="-1">3. 超跌选股 <a class="header-anchor" href="#_3-超跌选股" aria-label="Permalink to “3. 超跌选股”">​</a></h3><p>跌多了可能反弹（高风险）：</p><ul><li>股价跌破净资产</li><li>连续下跌后出现底部信号</li><li>机构大比例净买入</li></ul><h2 id="四、基本面选股" tabindex="-1">四、基本面选股 <a class="header-anchor" href="#四、基本面选股" aria-label="Permalink to “四、基本面选股”">​</a></h2><p>这是<strong>最重要的选股维度</strong>，也是价值投资的核心。</p><h3 id="_1-好行业" tabindex="-1">1. 好行业 <a class="header-anchor" href="#_1-好行业" aria-label="Permalink to “1. 好行业”">​</a></h3><p>先选赛道，再选公司：</p><table tabindex="0"><thead><tr><th>好的行业特点</th><th>举例</th></tr></thead><tbody><tr><td>需求稳定</td><td>医药、消费</td></tr><tr><td>行业集中度提升</td><td>行业龙头越做越大</td></tr><tr><td>政策支持</td><td>新能源、芯片</td></tr></tbody></table><h3 id="_2-好公司" tabindex="-1">2. 好公司 <a class="header-anchor" href="#_2-好公司" aria-label="Permalink to “2. 好公司”">​</a></h3><p>用财务指标筛选：</p><table tabindex="0"><thead><tr><th>指标</th><th>筛选标准</th></tr></thead><tbody><tr><td>ROE</td><td>&gt;15%</td></tr><tr><td>净利润增速</td><td>&gt;10%</td></tr><tr><td>资产负债率</td><td>&lt;60%</td></tr><tr><td>经营现金流</td><td>为正且稳定</td></tr></tbody></table><h3 id="_3-好价格" tabindex="-1">3. 好价格 <a class="header-anchor" href="#_3-好价格" aria-label="Permalink to “3. 好价格”">​</a></h3><p>好公司也要有好价格：</p><ul><li>PE在历史低位</li><li>PB在历史低位</li><li>股息率高于银行理财</li></ul><h2 id="五、三种选股策略对比" tabindex="-1">五、三种选股策略对比 <a class="header-anchor" href="#五、三种选股策略对比" aria-label="Permalink to “五、三种选股策略对比”">​</a></h2><table tabindex="0"><thead><tr><th>策略</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>消息面</td><td>快速，效率高</td><td>容易滞后，庄家骗线</td></tr><tr><td>技术面</td><td>有明确买卖点</td><td>滞后性，有假信号</td></tr><tr><td>基本面</td><td>稳健，中长期有效</td><td>需要研究能力，考验耐心</td></tr></tbody></table><blockquote><p>💡 <strong>建议</strong>：用基本面选股，用技术面择时。</p></blockquote><h2 id="六、新手选股建议" tabindex="-1">六、新手选股建议 <a class="header-anchor" href="#六、新手选股建议" aria-label="Permalink to “六、新手选股建议”">​</a></h2><ol><li><strong>从熟悉的行业开始</strong>：你用啥产品，就关注啥公司</li><li><strong>先看龙头</strong>：行业里最大、最赚钱的公司往往最稳</li><li><strong>不要追题材</strong>：小白追题材，十追九套</li><li><strong>控制数量</strong>：持仓不要超过3-5只</li></ol><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>你看好新能源行业，想要找一只新能源股票。你会从哪些维度来筛选？</p></blockquote><hr><p><strong>下一课预告</strong>：选好股票了，下一课学习<strong>读盘技巧</strong>——怎么看懂盘面的信号。</p>',45)])])}const _=a(l,[["render",i]]);export{p as __pageData,_ as default};
